#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

// Pybind contract: conv_transposed_3d_square_input_square_kernel_custom(Tensor x, Tensor weight) -> Tensor y
// Assumes stride=1, padding=0, dilation=1, groups=1, no bias.
at::Tensor conv_transposed3d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    TORCH_CHECK(x.dim() == 5, \"x must be 5D [N,C,D,H,W]\");
    TORCH_CHECK(weight.dim() == 5, \"weight must be 5D [Cin,Cout,kD,kH,kW]\");
    TORCH_CHECK(x.scalar_type() == at::kFloat, \"Only float32 supported\");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, \"Only float32 supported\");

    const auto N = x.size(0);
    const auto Cin = x.size(1);
    const auto inD = x.size(2);
    const auto inH = x.size(3);
    const auto inW = x.size(4);

    TORCH_CHECK(weight.size(0) == Cin, \"weight Cin must equal x Cin\");
    const auto Cout = weight.size(1);
    const auto kD = weight.size(2);
    const auto kH = weight.size(3);
    const auto kW = weight.size(4);

    const auto outD = inD + kD - 1;
    const auto outH = inH + kH - 1;
    const auto outW = inW + kW - 1;

    at::Tensor y = at::empty({N, Cout, outD, outH, outW}, x.options());
    EXEC_NPU_CMD(aclnnConvTransposed3dSquareInputSquareKernelCustom, x, weight, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl(\"conv_transposed_3d_square_input_square_kernel_custom\", &conv_transposed3d_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def(\"conv_transposed_3d_square_input_square_kernel_custom\",
          &conv_transposed3d_impl_npu,
          \"ConvTranspose3d (stride=1,pad=0) (ConvTransposed3dSquareInputSquareKernelCustom on NPU)\");
}
